/**
 * Handler action (what to do with the part).
 */

public enum HandlerAction {
    
    case reveal
    case hash(algorithm: HashAlgorithm
    )
    /**
     * Reveal the data (like `Reveal`) and have the verifier evaluate a
     * comparison against it. For `compute_reveal` this behaves as `Reveal`;
     * the assertion spec is carried to the verifier's `reveal_config`.
     */
    case assert(op: AssertOp, 
        /**
         * How to type the comparison (ordering ops + `between`).
         */valueType: AssertValueType?, 
        /**
         * Operands as strings (parsed per `value_type` by the verifier).
         */value: String?, min: String?, max: String?, inclusive: Bool?, 
        /**
         * Candidate values for `in`.
         */values: [String]?
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeHandlerAction: FfiConverterRustBuffer {
    typealias SwiftType = HandlerAction

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> HandlerAction {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .reveal
        
        case 2: return .hash(algorithm: try FfiConverterTypeHashAlgorithm.read(from: &buf)
        )
        
        case 3: return .assert(op: try FfiConverterTypeAssertOp.read(from: &buf), valueType: try FfiConverterOptionTypeAssertValueType.read(from: &buf), value: try FfiConverterOptionString.read(from: &buf), min: try FfiConverterOptionString.read(from: &buf), max: try FfiConverterOptionString.read(from: &buf), inclusive: try FfiConverterOptionBool.read(from: &buf), values: try FfiConverterOptionSequenceString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: HandlerAction, into buf: inout [UInt8]) {
        switch value {
        
        
        case .reveal:
            writeInt(&buf, Int32(1))
        
        
        case let .hash(algorithm):
            writeInt(&buf, Int32(2))
            FfiConverterTypeHashAlgorithm.write(algorithm, into: &buf)
            
        
        case let .assert(op,valueType,value,min,max,inclusive,values):
            writeInt(&buf, Int32(3))
            FfiConverterTypeAssertOp.write(op, into: &buf)
            FfiConverterOptionTypeAssertValueType.write(valueType, into: &buf)
            FfiConverterOptionString.write(value, into: &buf)
            FfiConverterOptionString.write(min, into: &buf)
            FfiConverterOptionString.write(max, into: &buf)
            FfiConverterOptionBool.write(inclusive, into: &buf)
            FfiConverterOptionSequenceString.write(values, into: &buf)
            
        }
    }
}


