/**
 * Callback interface for receiving proof progress updates.
 *
 * Implement this on the Swift/Kotlin side to receive real-time progress
 * from the Rust prover. Each call includes:
 * - `step`: machine-readable step name (e.g. "MPC_SETUP")
 * - `progress`: 0.0–1.0 fraction
 * - `message`: human-readable description
 */
public protocol ProgressCallback : AnyObject {
    
    func onProgress(step: String, progress: Double, message: String) 
    
}

// Magic number for the Rust proxy to call using the same mechanism as every other method,
// to free the callback once it's dropped by Rust.
private let IDX_CALLBACK_FREE: Int32 = 0
// Callback return codes
private let UNIFFI_CALLBACK_SUCCESS: Int32 = 0
private let UNIFFI_CALLBACK_ERROR: Int32 = 1
private let UNIFFI_CALLBACK_UNEXPECTED_ERROR: Int32 = 2

// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceProgressCallback {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    static var vtable: UniffiVTableCallbackInterfaceProgressCallback = UniffiVTableCallbackInterfaceProgressCallback(
        onProgress: { (
            uniffiHandle: UInt64,
            step: RustBuffer,
            progress: Double,
            message: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterCallbackInterfaceProgressCallback.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.onProgress(
                     step: try FfiConverterString.lift(step),
                     progress: try FfiConverterDouble.lift(progress),
                     message: try FfiConverterString.lift(message)
                )
            }

            
            let writeReturn = { () }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            let result = try? FfiConverterCallbackInterfaceProgressCallback.handleMap.remove(handle: uniffiHandle)
            if result == nil {
                print("Uniffi callback interface ProgressCallback: handle missing in uniffiFree")
            }
        }
    )
}

private func uniffiCallbackInitProgressCallback() {
    uniffi_tlsn_mobile_fn_init_callback_vtable_progresscallback(&UniffiCallbackInterfaceProgressCallback.vtable)
}

